using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use an empty resolver so nothing is resolvable.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolves nothing
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata: {info!.Type.Name}");
}
else
{
    Console.WriteLine("Metadata for Person is NOT available (no exception thrown).");
}

// Confirm the happy-path probe works too
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"Probe succeeded on full resolver: {info2!.Type.Name}");
}

public record Person(string Name, int Age);

